import{_ as t,o as a,c as i,ae as o}from"./chunks/framework.BD9pLfSD.js";const h=JSON.parse('{"title":"xB77 Ecosystem Integration and Sponsor Alignment","description":"","frontmatter":{},"headers":[],"relativePath":"docs/sponsors.md","filePath":"docs/sponsors.md"}'),n={name:"docs/sponsors.md"};function r(s,e,l,d,c,u){return a(),i("div",null,[...e[0]||(e[0]=[o('<h1 id="xb77-ecosystem-integration-and-sponsor-alignment" tabindex="-1">xB77 Ecosystem Integration and Sponsor Alignment <a class="header-anchor" href="#xb77-ecosystem-integration-and-sponsor-alignment" aria-label="Permalink to &quot;xB77 Ecosystem Integration and Sponsor Alignment&quot;">​</a></h1><h2 id="_1-executive-summary" tabindex="-1">1. Executive Summary <a class="header-anchor" href="#_1-executive-summary" aria-label="Permalink to &quot;1. Executive Summary&quot;">​</a></h2><p>xB77 is designed as a modular aggregator of the most advanced technologies in the Solana and ZK ecosystems. Our goal is to demonstrate that privacy is not a niche requirement but a fundamental prerequisite for the institutional adoption of autonomous agents.</p><h2 id="_2-strategic-integration-by-sponsor" tabindex="-1">2. Strategic Integration by Sponsor <a class="header-anchor" href="#_2-strategic-integration-by-sponsor" aria-label="Permalink to &quot;2. Strategic Integration by Sponsor&quot;">​</a></h2><h3 id="_2-1-helius-real-time-forensics-and-observability" tabindex="-1">2.1 Helius: Real-Time Forensics and Observability <a class="header-anchor" href="#_2-1-helius-real-time-forensics-and-observability" aria-label="Permalink to &quot;2.1 Helius: Real-Time Forensics and Observability&quot;">​</a></h3><ul><li><strong>Status:</strong> <code>FUNCTIONAL MVP (Simulated Data)</code></li><li><strong>Implementation:</strong> xB77 utilizes Helius RPCs and Webhooks as the &quot;Sensory System&quot; of the agent.</li><li><strong>Value Added:</strong> Our agents perform proactive risk assessment. The Hub displays a &quot;Forensic Radar&quot; that visualizes the risk score of destination addresses before committing funds.</li></ul><h3 id="_2-2-light-protocol-shielded-liquidity-and-compression" tabindex="-1">2.2 Light Protocol: Shielded Liquidity and Compression <a class="header-anchor" href="#_2-2-light-protocol-shielded-liquidity-and-compression" aria-label="Permalink to &quot;2.2 Light Protocol: Shielded Liquidity and Compression&quot;">​</a></h3><ul><li><strong>Status:</strong> <code>INTEGRATION ROADMAP</code></li><li><strong>Implementation:</strong> Light Protocol is our target <strong>Shielded Payment Rail</strong>. We are designing the SDK to wrap Light&#39;s v3 ZK-compression architecture.</li><li><strong>Value Added:</strong> The current MVP simulates the &quot;Shielded&quot; state in the UI/Indexer to demonstrate the UX of private transfers before final on-chain binding.</li></ul><h3 id="_2-3-arcium-confidential-state-and-strategic-vaults" tabindex="-1">2.3 Arcium: Confidential State and Strategic Vaults <a class="header-anchor" href="#_2-3-arcium-confidential-state-and-strategic-vaults" aria-label="Permalink to &quot;2.3 Arcium: Confidential State and Strategic Vaults&quot;">​</a></h3><ul><li><strong>Status:</strong> <code>ARCHITECTURAL PROPOSAL</code></li><li><strong>Implementation:</strong> Designed for storing sensitive operational metadata (Inventory, Vendor ratings).</li><li><strong>Value Added:</strong> Demonstrates how strategic &quot;Business Intelligence&quot; remains private even during external audits.</li></ul><h3 id="_2-4-starpay-fiat-to-privacy-gateway" tabindex="-1">2.4 Starpay: Fiat-to-Privacy Gateway <a class="header-anchor" href="#_2-4-starpay-fiat-to-privacy-gateway" aria-label="Permalink to &quot;2.4 Starpay: Fiat-to-Privacy Gateway&quot;">​</a></h3><ul><li><strong>Status:</strong> <code>FUNCTIONAL MVP (Mocked Bridge)</code></li><li><strong>Implementation:</strong> Simulated integration of Virtual Card infrastructure to fund the initial pool.</li><li><strong>Value Added:</strong> Provides the narrative for legacy enterprise on-boarding via <strong>USD1</strong> tokens.</li></ul><h3 id="_2-5-range-protocol-institutional-compliance-and-guardrails" tabindex="-1">2.5 Range Protocol: Institutional Compliance and Guardrails <a class="header-anchor" href="#_2-5-range-protocol-institutional-compliance-and-guardrails" aria-label="Permalink to &quot;2.5 Range Protocol: Institutional Compliance and Guardrails&quot;">​</a></h3><ul><li><strong>Status:</strong> <code>FUNCTIONAL MVP (Local Guardrails)</code></li><li><strong>Implementation:</strong> Every transaction in the xB77 SDK is intercepted by a local compliance screening layer.</li><li><strong>Value Added:</strong> Demonstrates &quot;Permissioned Privacy&quot; by blocking high-risk destinations in the Hub.</li></ul><h3 id="_2-6-noir-aztec-zero-knowledge-identity-and-selective-disclosure" tabindex="-1">2.6 Noir (Aztec): Zero-Knowledge Identity and Selective Disclosure <a class="header-anchor" href="#_2-6-noir-aztec-zero-knowledge-identity-and-selective-disclosure" aria-label="Permalink to &quot;2.6 Noir (Aztec): Zero-Knowledge Identity and Selective Disclosure&quot;">​</a></h3><ul><li><strong>Status:</strong> <code>INTEGRATION ROADMAP (Circuits under development)</code></li><li><strong>Implementation:</strong> Noir is the engine for Agent Identity Badges and Certified Selective Disclosure.</li><li><strong>Value Added:</strong> The Hub already includes the UI for &quot;View Invoice&quot; which uses the logic that Noir will eventually prove mathematically.</li></ul><h3 id="_2-7-kamino-finance-capital-efficiency-and-self-sustainability" tabindex="-1">2.7 Kamino Finance: Capital Efficiency and Self-Sustainability <a class="header-anchor" href="#_2-7-kamino-finance-capital-efficiency-and-self-sustainability" aria-label="Permalink to &quot;2.7 Kamino Finance: Capital Efficiency and Self-Sustainability&quot;">​</a></h3><ul><li>Implementation: Kamino vaults serve as the &quot;Savings Account&quot; for the autonomous CFO.</li><li>Value Added: xB77 introduces the concept of &quot;Invisible Yielding&quot;. By managing liquidity thresholds autonomously, agents ensure that their own operation cost (gas and compute fees) is covered by the interest generated from their idle capital.</li></ul><h2 id="_3-conclusion" tabindex="-1">3. Conclusion <a class="header-anchor" href="#_3-conclusion" aria-label="Permalink to &quot;3. Conclusion&quot;">​</a></h2><p>xB77 is not a standalone product; it is a synergistic layer that connects the best of Solana&#39;s infrastructure to the needs of the future autonomous economy.</p>',20)])])}const m=t(n,[["render",r]]);export{h as __pageData,m as default};
